
(()=>{const $=s=>document.querySelector(s), $$=s=>Array.from(document.querySelectorAll(s)); const gates=['Mission Contract','Role Allocation','Tool Scope','Work Trace','ProofBundle','Verifier Mesh','Risk Ledger','Settlement Check','Chronicle Entry','Human Review']; const presets={economy:'Coordinate AGIJobManager settlement, Evidence Docket publication, Chronicle memory, and human review without granting public authority.',market:'Produce a proof-settled market brief with assumptions, claim boundaries, and validator-ready evidence.',software:'Simulate a validator-ready software work packet with patch artifact, test gate, risk ledger, and rollback path.',dispute:'Route a contested work result through challenge window, validator disagreement, and human review.',boundary:'Verify that a public-safe mission produces a docket without personal data, wallet action, or external network calls.'}; let state={mode:'institution',step:0,timer:null,trace:[]}; function score(){const m=state.mode, s=state.step; const base=m==='swarm'?[90,18,12,8,16,78]:m==='fixed'?[70,58,52,44,42,42]:[78,92,88,86,82,18]; return {output:Math.min(100,base[0]+s*1),proof:Math.min(100,base[1]+s*5),validation:Math.min(100,base[2]+s*5),settlement:Math.min(100,base[3]+s*5),reuse:Math.min(100,base[4]+s*4),debt:Math.max(0,base[5]-s*6)}} function verdict(x){if(x.proof<40)return 'ACTIVITY_WITHOUT_AUTHORITY'; if(x.validation<60)return 'RETURN_TO_VALIDATION'; if(x.settlement<70)return 'HUMAN_REVIEW_BEFORE_SETTLEMENT'; if(x.reuse<70)return 'CHRONICLE_READY_FOR_REVIEW'; return 'PROOF_GOVERNED_INSTITUTION_READY_FOR_HUMAN_REVIEW'} function render(){const x=score(); ['output','proof','validation','settlement','reuse','debt'].forEach(k=>{const el=$(`[data-metric="${k}"]`); if(el)el.textContent=x[k]}); const v=verdict(x); const ve=$('[data-verdict]'); if(ve)ve.textContent=v.replaceAll('_',' · '); const ge=$('[data-gates]'); if(ge)ge.innerHTML=gates.map((g,i)=>`<div class="g42-gate ${i<state.step?'done':i===state.step?'running':''}"><small>${String(i+1).padStart(2,'0')}</small><b>${g}</b></div>`).join(''); const log=$('[data-log]'); if(log)log.textContent=state.trace.join('\n')||'Awaiting mission. Select a model and run the proof cycle.'; $$('[data-model]').forEach(b=>b.classList.toggle('active',b.dataset.model===state.mode)); const d=$('[data-docket]'); if(d)d.textContent=JSON.stringify(docket(),null,2)} function preset(){const sel=$('[data-preset]'), area=$('[data-objective]'); if(sel&&area)area.value=presets[sel.value]||presets.economy} function run(){clearInterval(state.timer); state.step=0; state.trace=[`0 · Mission contracted · ${new Date().toISOString()}`,`1 · Coordination model selected · ${state.mode}`,`2 · Public-safe boundary · no wallet · no network · no user data wanted`]; render(); state.timer=setInterval(()=>{state.step++; state.trace.push(`${state.trace.length} · ${gates[Math.min(state.step-1,gates.length-1)]} · local simulated pass`); render(); if(state.step>=gates.length){clearInterval(state.timer);state.trace.push(`${state.trace.length} · HUMAN_REVIEW_REQUIRED · no production authority granted`); render()}},520)} function reset(){clearInterval(state.timer); state.step=0; state.trace=[]; render()} function docket(){const x=score(); return {receiptType:'GoalOSCoordinationDocket',version:'v42',generatedAt:new Date().toISOString(),missionPreset:($('[data-preset]')||{}).value||'economy',objective:(($('[data-objective]')||{}).value||'').slice(0,1200),coordinationModel:state.mode,law:'Maximum coordination = verified useful work per unit of risk, cost, latency, and proof debt.',equation:'AI Work = Output × Proof × Validation × Settlement × Reuse',verdict:verdict(x),metrics:x,gates:gates.map((g,i)=>({gate:g,status:i<state.step?'passed':i===state.step?'running':'queued'})),trace:state.trace,boundary:{browserLocal:true,noWallet:true,noNetwork:true,noUserDataWanted:true,noProductionAuthority:true}}} function download(){const blob=new Blob([JSON.stringify(docket(),null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='goalos-coordination-docket-v42.json'; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),500)} async function copy(){try{await navigator.clipboard.writeText(`GoalOS Coordination Lab: ${verdict(score()).replaceAll('_',' ')}. No wallet, no network, no user data wanted.`)}catch{}} document.addEventListener('DOMContentLoaded',()=>{$$('[data-model]').forEach(b=>b.addEventListener('click',()=>{state.mode=b.dataset.model;render()})); const sel=$('[data-preset]'); if(sel)sel.addEventListener('change',preset); const runb=$('[data-run]'); if(runb)runb.addEventListener('click',run); const resetb=$('[data-reset]'); if(resetb)resetb.addEventListener('click',reset); const dl=$('[data-download]'); if(dl)dl.addEventListener('click',download); const cp=$('[data-copy]'); if(cp)cp.addEventListener('click',copy); preset(); render();});})();
